import javax.xml.parsers.*;  // To parse XML data using DOM parser, use 'javax.' prefix with JDK'10+ versions and above as they come along in parsing xml files from standard library
// import org., for older Java Versions (<JDK7) you have to include the corresponding javax.xml.* packages – if present on your classpath while running, otherwise use 'org.' prefix with JDK'10+ versions and above as they come along in parsing xml files from standard library
import org.w3c.dom.*; // To parse XML data using DOM parser (optional), uses Java API for reading the file which is not a framework but available via stdlib – if present on your classpath while running, otherwise use 'org.' prefix with JDK'10+ versions and above as they come along in parsing xml files from standard library
import org.xml.sax.*; // To parse XML data using SAX parser (optional), uses Java API for reading the file which is not a framework but available via stdlib – if present on your classpath while running, otherwise use 'org.' prefix with JDK'10+ versions and above as they come along in parsing xml files from standard library
import java.io.*; // To read XML data using IO methods (optional), uses Java API for reading the file which is not a framework but available via stdlib – if present on your classpath while running, otherwise use 'java.' prefix with JDK'10+ versions and above as they come along in parsing xml files from standard library
// import other necessary libraries (if any) required to parse XML data based upon the usage requirement. If not using a specific parser such as SAX or DOM you should comment these lines out for clarity, otherwise uncomment them accordingly with your chosen choice of method – if present on classpath when running application then use 'java.' prefix else it would need further imports to include in stdlib
  
public void parseXML(String fileName) { // Method definition - takes a filename as parameter (functional dependency, not covered by the rules below), returns nothing but throws exception if no such XML exists at specified location. Use try with resources for cleanup of stream and document on end – in case any exceptions occur during execution
    DocumentBuilderFactory dbFactory = DocumentBuilderFactory.newInstance(); // Create a factory that can create out-of-the box the parser, which is an approach used to parse XML data from file or InputStreams (optional) - using Java API'10+ versions and above as they come along in parsing xml files 
    try(DocumentBuilder builder = dbFactory.newDocumentBuilder()) { // Use Document Builder for handling our document tree, provides a more flexible way of adding elements to the DOM or XML file without worrying about markup compatibility (optional) - using Java API'10+ versions and above as they come along in parsing xml files
        Document doc = builder.parse(new File(fileName)); // Parse this document into its internal tree, throws SAXException if any exception occurs during the parse process – use try-catch block for handling exceptions gracefully (optional) - using Java API'10+ versions and above as they come along in parsing xml files
        doc.getDocumentElement().normalize(); // Necessary to ensure that XML is readable, throws a DocumentException if any exception occurs – use try-catch block for handling exceptions gracefully (optional) - using Java API'10+ versions and above as they come along in parsing xml files
        System.out.println("XML Parsed Successfully!"); // If the file is readable, XML has been parsed correctly so this will print a success message to console – use try-catch block for handling exceptions gracefully (optional) - using Java API'10+ versions and above as they come along in parsing xml files
    } catch(ParserConfigurationException pce){ // Catching exception if any configuration related issues occur during the creation of parser, throws a ParserConfigurationExcpetion is when required feature not available on current environment – use try-catch block for handling exceptions gracefully (optional) - using Java API'10+ versions and above as they come along in parsing xml files
        pce.printStackTrace(); // Prints the exception details to console if any occur during execution of program, not needed here but shown while catching it – use try-catch block for handling exceptions gracefully (optional) - using Java API'10+ versions and above as they come along in parsing xml files
    } catch(SAXException sae){ // Catching exception if any SAX related issues occur during the parse process, throws a SAX Exception is when required feature not available on current environment – use try-catch block for handling exceptions gracefully (optional) - using Java API'10+ versions and above as they come along in parsing xml files
        sae.printStackTrace(); // Prints the exception details to console if any occur during execution of program, not needed here but shown while catching it – use try-catch block for handling exceptions gracefully (optional) - using Java API'10+ versions and above as they come along in parsing xml files
    } catch(IOException ie){ // Catching exception if any I/O related issues occur during the parse process, throws an IOException is when required feature not available on current environment – use try-catch block for handling exceptions gracefully (optional) - using Java API'10+ versions and above as they come along in parsing xml files
        ie.printStackTrace(); // Prints the exception details to console if any occur during execution of program, not needed here but shown while catching it – use try-catch block for handling exceptions gracefully (optional) - using Java API'10+ versions and above as they come along in parsing xml files
    } catch(DocumentException de){ // Catching exception if any document related issues occur during the parse process, throws a Document Exception is when required feature not available on current environment – use try-catch block for handling exceptions gracefully (optional) - using Java API'10+ versions and above as they come along in parsing xml files
        de.printStackTrace(); // Prints exception details to console if any occur during execution of program, not needed here but shown while catching it – use try-catch block for handling exceptions gracefully (optional) - using Java API'10+ versions and above as they come along in parsing xml files
    } catch(Exception e){ // General exception handler to handle all other cases when no specific case matches, not needed here but shown while catching it – use try-catch block for handling exceptions gracefully (optional) - using Java API'10+ versions and above as they come along in parsing xml files
        System.out.println("An error has occurred: " + e); // Prints exception details to console if any occur during execution of program, not needed here but shown while catching it – use try-catch block for handling exceptions gracefully (optional) - using Java API'10+ versions and above as they come along in parsing xml files
    }  
}